    public static string GetName(int stuffId) => _names.TryGetValue(stuffId, out var n) ? n : "";

    internal static string GetAllJson()
    {
        var sb = new System.Text.StringBuilder("{");
        bool first = true;
        foreach (var kv in _names)
        {
            if (!first) sb.Append(",");
            first = false;
            sb.Append(kv.Key).Append(":\"").Append(kv.Value).Append("\"");
        }
        sb.Append("}");
        return sb.ToString();
    }
